// State transition hook (entity-specific, not from factory)
import { useMutation, useQueryClient } from '@tanstack/react-query'

export function useTransitionStack() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: ({ id, toState }: { id: string; toState: string }) =>
      stackApi.transition(id, toState),
    onSuccess: (result) => {
      stackCollection.utils.writeUpsert(result)
      queryClient.invalidateQueries({ queryKey: stackKeys.lists() })
    },
  })
}
